INSERT INTO "quotes" ("id", "text", "category", "is_featured", "display_order", "is_active", "created_at", "updated_at") VALUES ('b06e2ed9-72fa-4f5c-8b6e-36149ce977af', 'Faith grows quietly where compassion becomes natural.', 'Compassion', FALSE, 3, TRUE, '2026-03-09T11:40:35.137Z', '2026-03-09T11:40:35.137Z');
INSERT INTO "quotes" ("id", "text", "category", "is_featured", "display_order", "is_active", "created_at", "updated_at") VALUES ('bb159f8a-8f6a-4dd8-abd8-58c41e46e742', 'Discipline is not punishment; it is the protection of the soul.', 'Inner Discipline', FALSE, 4, TRUE, '2026-03-09T11:40:35.616Z', '2026-03-09T11:40:35.616Z');
INSERT INTO "quotes" ("id", "text", "category", "is_featured", "display_order", "is_active", "created_at", "updated_at") VALUES ('fc32fdaf-b997-4c9a-9c61-f6767618f5e7', 'The world changes slowly, but the heart can change in a single moment.', 'Self Awareness', FALSE, 5, TRUE, '2026-03-09T11:40:35.878Z', '2026-03-09T11:40:35.878Z');
INSERT INTO "quotes" ("id", "text", "category", "is_featured", "display_order", "is_active", "created_at", "updated_at") VALUES ('d91e05f3-9a6f-4348-9b08-3ce4ea412ce2', 'Human beings search across the world for meaning, yet the doorway is always within their own awareness.', 'Self Awareness', TRUE, 0, TRUE, '2026-03-09T11:40:36.120Z', '2026-03-09T11:40:36.120Z');
INSERT INTO "quotes" ("id", "text", "category", "is_featured", "display_order", "is_active", "created_at", "updated_at") VALUES ('754abffc-bb70-420b-bd34-31aeba3a3f0b', 'Compassion is not an act of will but a quality of understanding.', 'Compassion', FALSE, 6, TRUE, '2026-03-09T11:40:36.376Z', '2026-03-09T11:40:36.376Z');
INSERT INTO "quotes" ("id", "text", "category", "is_featured", "display_order", "is_active", "created_at", "updated_at") VALUES ('f55a61b4-92d5-441d-b117-d8395142ad3c', 'True discipline arises from love of the goal, not fear of failure.', 'Inner Discipline', FALSE, 7, TRUE, '2026-03-09T11:40:36.881Z', '2026-03-09T11:40:36.881Z');
INSERT INTO "quotes" ("id", "text", "category", "is_featured", "display_order", "is_active", "created_at", "updated_at") VALUES ('52f8cebf-c0f3-4565-954c-e5c79aabf4bd', 'Ethical conduct is not following rules but living from clarity.', 'Ethical Conduct', FALSE, 8, TRUE, '2026-03-09T11:40:37.128Z', '2026-03-09T11:40:37.128Z');
INSERT INTO "quotes" ("id", "text", "category", "is_featured", "display_order", "is_active", "created_at", "updated_at") VALUES ('4e829e88-6f54-4f41-b72f-d49e1d07d896', 'We are not separate beings seeking connection; we are connection expressing as separate beings.', 'Human Unity', FALSE, 9, TRUE, '2026-03-09T11:40:37.380Z', '2026-03-09T11:40:37.380Z');
INSERT INTO "quotes" ("id", "text", "category", "is_featured", "display_order", "is_active", "created_at", "updated_at") VALUES ('933392f2-320a-4a60-99c0-1258dcade30b', 'In silence, the mind finds its natural rhythm and the heart its native language.', 'Peace and Reflection', FALSE, 10, TRUE, '2026-03-09T11:40:37.695Z', '2026-03-09T11:40:37.695Z');
INSERT INTO "quotes" ("id", "text", "category", "is_featured", "display_order", "is_active", "created_at", "updated_at") VALUES ('c64d4c02-4080-4272-b99b-68e765337b6d', 'Awareness is the mirror in which truth recognizes itself.', 'Self Awareness', FALSE, 11, TRUE, '2026-03-09T11:40:38.356Z', '2026-03-09T11:40:38.356Z');
INSERT INTO "quotes" ("id", "text", "category", "is_featured", "display_order", "is_active", "created_at", "updated_at") VALUES ('c07e093e-c03d-4d57-93ac-3505d6f8d7c2', 'To be ethical is to act from understanding rather than from impulse.', 'Ethical Conduct', FALSE, 12, TRUE, '2026-03-09T11:40:38.618Z', '2026-03-09T11:40:38.618Z');
INSERT INTO "quotes" ("id", "text", "category", "is_featured", "display_order", "is_active", "created_at", "updated_at") VALUES ('e344089d-245d-4fdf-a09f-0a384b9c070c', 'Unity is not something to achieve; it is something to recognize.', 'Human Unity', FALSE, 13, TRUE, '2026-03-09T11:40:38.862Z', '2026-03-09T11:40:38.862Z');
INSERT INTO "quotes" ("id", "text", "category", "is_featured", "display_order", "is_active", "created_at", "updated_at") VALUES ('5d83fb09-b7f6-4adc-ad7c-f8c177a45530', 'Compassion begins where judgment ends.', 'Compassion', FALSE, 14, TRUE, '2026-03-09T11:40:39.230Z', '2026-03-09T11:40:39.230Z');
INSERT INTO "quotes" ("id", "text", "category", "is_featured", "display_order", "is_active", "created_at", "updated_at") VALUES ('e3caa20d-aca1-4ffe-bf84-1cdbb440f35d', 'The quiet mind hears what the busy mind cannot imagine.', 'Peace and Reflection', FALSE, 15, TRUE, '2026-03-09T11:40:41.245Z', '2026-03-09T11:40:41.245Z');
INSERT INTO "quotes" ("id", "text", "category", "is_featured", "display_order", "is_active", "created_at", "updated_at") VALUES ('54cfe4cd-08a4-44f9-9d03-019635cdb579', 'Self-observation is the first act of freedom.', 'Self Awareness', FALSE, 16, TRUE, '2026-03-09T11:40:41.574Z', '2026-03-09T11:40:41.574Z');
INSERT INTO "quotes" ("id", "text", "category", "is_featured", "display_order", "is_active", "created_at", "updated_at") VALUES ('fab65000-060e-4d7e-94b2-477e90239deb', 'Consistency in small things creates the capacity for greatness in all things.', 'Inner Discipline', FALSE, 17, TRUE, '2026-03-09T11:40:41.834Z', '2026-03-09T11:40:41.834Z');
INSERT INTO "quotes" ("id", "text", "category", "is_featured", "display_order", "is_active", "created_at", "updated_at") VALUES ('75186f8e-5252-4b0c-9b79-6964713b0eb4', 'Peace begins when the mind becomes honest with itself.', 'Peace and Reflection', FALSE, 2, TRUE, '2026-03-09T11:40:34.872Z', '2026-03-09T11:43:43.407Z');
INSERT INTO "quotes" ("id", "text", "category", "is_featured", "display_order", "is_active", "created_at", "updated_at") VALUES ('2359ca1c-fead-4e57-8788-8e5acf6e6307', 'The heart becomes clear when it stops arguing with truth.', 'Self Awareness', FALSE, 1, TRUE, '2026-03-09T11:40:32.728Z', '2026-03-09T11:43:44.569Z');
